nodes.notes:
Google Tasks — view, add, update, complete, or delete tasks.

Actions:
  get — list tasks. Use for "what are my tasks", "show my to-do list".
  add — create a new task. Use for "add a task", "remind me to".
  update — modify a task's title, notes, or due date. Requires task_id from a prior get call. Only include fields you want to change.
  complete — mark a task done. Requires task_id from a prior get call.
  delete — remove a task. Requires task_id from a prior get call.

Rules:
- task_id comes from a prior get call. Do not fabricate task IDs.
- due is YYYY-MM-DD format.
- For update, only send fields that should change. Omitted fields remain unchanged.

---schema
{
  "action": {
    "type": "string",
    "description": "One of: get, add, update, complete, delete",
    "required": true
  },
  "title": {
    "type": "string",
    "description": "Task title. For: add, update"
  },
  "notes": {
    "type": "string",
    "description": "Task notes or details. For: add, update"
  },
  "due": {
    "type": "string",
    "description": "Due date YYYY-MM-DD. For: add, update"
  },
  "task_id": {
    "type": "string",
    "description": "Task ID from a prior get call. For: update, complete, delete"
  },
  "show_completed": {
    "type": "boolean",
    "description": "Include completed tasks. Default false. For: get"
  }
}

parameters.jsCode:
// Parse input - handle both JSON string and object formats
let data;

if (typeof items[0].json.body === 'string') {
  data = JSON.parse(items[0].json.body);
} else if (typeof items[0].json.body === 'object') {
  data = items[0].json.body;
} else {
  data = items[0].json;
}

const action = (data.action || 'get').toLowerCase();
const title = data.title || '';
const notes = data.notes || '';
const taskId = data.task_id || '';
const showCompleted = data.show_completed || false;
let due = data.due || '';

// Convert date to ISO format if provided
if (due && due.match(/^\d{4}-\d{2}-\d{2}$/)) {
  due = due + 'T00:00:00.000Z';
}

return [{
  json: {
    action: action,
    title: title,
    notes: notes,
    taskId: taskId,
    due: due,
    showCompleted: showCompleted
  }
}];

// Format tasks for voice
const allTasks = items.map(item => item.json);
const showCompleted = $('Parse Parameters').item.json.showCompleted;

const tasks = allTasks
  .filter(t => t.status !== 'completed' || showCompleted)
  .map(t => {
    let dueStr = '';
    if (t.due) {
      const due = new Date(t.due);
      const today = new Date();
      today.setHours(0,0,0,0);
      const tomorrow = new Date(today);
      tomorrow.setDate(tomorrow.getDate() + 1);

      if (due.toDateString() === today.toDateString()) dueStr = 'today';
      else if (due.toDateString() === tomorrow.toDateString()) dueStr = 'tomorrow';
      else dueStr = due.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' });
    }
    return { id: t.id, title: t.title, notes: t.notes || '', due: dueStr, dueRaw: t.due || null, completed: t.status === 'completed' };
  })
  .sort((a, b) => {
    if (!a.dueRaw && !b.dueRaw) return 0;
    if (!a.dueRaw) return 1;
    if (!b.dueRaw) return -1;
    return new Date(a.dueRaw) - new Date(b.dueRaw);
  });

let message = '';
if (tasks.length === 0) {
  message = 'Your task list is empty.';
} else if (tasks.length === 1) {
  const t = tasks[0];
  message = `You have one task: ${t.title}${t.due ? ', due ' + t.due : ''}.`;
} else {
  message = `You have ${tasks.length} tasks. `;
  const summaries = tasks.slice(0, 5).map(t => t.title + (t.due ? ' due ' + t.due : ''));
  message += summaries.join('. ') + '.';
  if (tasks.length > 5) message += ` Plus ${tasks.length - 5} more.`;
}

return [{ json: { message, action: 'get', tasks } }];

// Format success response
const task = $input.item.json;
const title = task.title || 'your task';

let message = '';
if (task.due) {
  const dueDate = new Date(task.due);
  const options = { weekday: 'long', month: 'long', day: 'numeric' };
  const formattedDue = dueDate.toLocaleDateString('en-US', options);
  message = `Done. Added ${title} to your tasks, due ${formattedDue}.`;
} else {
  message = `Done. Added ${title} to your tasks.`;
}

return {
  message: message,
  action: 'add',
  task: { id: task.id, title: task.title, notes: task.notes || '', due: task.due || null, status: task.status }
};

// Format success
const task = $input.item.json;
const title = task.title || 'the task';

return {
  message: `Done. Marked ${title} as complete.`,
  action: 'complete',
  task: { id: task.id, title: task.title, status: task.status }
};

// Format success
return {
  message: 'Done. Task deleted.',
  action: 'delete',
  deleted: true
};

const task = $input.item.json;
const params = $('Parse Parameters').item.json;
const title = task.title || params.title || 'the task';

const changes = [];
if (params.title) changes.push('title');
if (params.notes) changes.push('notes');
if (params.due) changes.push('due date');
const what = changes.length > 0 ? changes.join(', ') : 'details';

return [{ json: { message: `Done. Updated ${what} for ${title}.`, action: 'update', task: { id: task.id, title: task.title, notes: task.notes || '', due: task.due || null } } }];

// Format error for voice
const errorData = items[0].json;
let errorMsg = errorData.message || errorData.error || 'Unknown error';

if (errorMsg.includes('authorization') || errorMsg.includes('token') || errorMsg.includes('invalid_grant')) {
  errorMsg = 'Google Tasks authentication failed. Please re-authorize in n8n.';
} else if (errorMsg.includes('Credential')) {
  errorMsg = 'Google Tasks credentials not found in n8n.';
} else if (errorMsg.includes('not found') || errorMsg.includes('404')) {
  errorMsg = 'Task not found. It may have been deleted.';
}

return [{ json: {
  message: `Error: ${errorMsg}`,
  error: true
}}];
